import{c as e,Q as o,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"Beyond the Context Window: Memory vs. Long-Context for LLM Agents","description":"","frontmatter":{"title":"Beyond the Context Window: Memory vs. Long-Context for LLM Agents","authors":"Tian Luo, Yijun Yang, Jiarui Liu, Yuhui Zhang, Hang Li","published":"2026-03-05T00:00:00.000Z","source":"https://arxiv.org/abs/2603.04814"},"headers":[],"relativePath":"research/papers/2026-03-05-beyond-context-window-memory-vs-longcontext-2603-04814.md","filePath":"research/papers/2026-03-05-beyond-context-window-memory-vs-longcontext-2603-04814.md","lastUpdated":1779901665000}'),a={name:"research/papers/2026-03-05-beyond-context-window-memory-vs-longcontext-2603-04814.md"};function s(i,t,c,d,l,h){return o(),r("div",null,[...t[0]||(t[0]=[n(`<h1 id="beyond-the-context-window-memory-vs-long-context-for-llm-agents" tabindex="-1">Beyond the Context Window: Memory vs. Long-Context for LLM Agents <a class="header-anchor" href="#beyond-the-context-window-memory-vs-long-context-for-llm-agents" aria-label="Permalink to &quot;Beyond the Context Window: Memory vs. Long-Context for LLM Agents&quot;">​</a></h1><p><strong>Authors</strong>: Tian Luo, Yijun Yang, Jiarui Liu, Yuhui Zhang, Hang Li <strong>Published</strong>: March 5, 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2603.04814" target="_blank" rel="noreferrer">https://arxiv.org/abs/2603.04814</a><strong>arXiv ID</strong>: 2603.04814 <strong>Categories</strong>: cs.AI, cs.CL, cs.LG</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>Systematic empirical comparison of memory-based and long-context approaches for LLM agents operating over multi-turn conversations. Long-context (keeping full history in context window) outperforms memory-based compression by 33.4–35.2 percentage points in accuracy. However, memory becomes economically favorable after approximately 10 conversation turns at 100K token context sizes. Memory systems achieve 35:1 compression but with significant information loss.</p><hr><h2 id="problem-setting" tabindex="-1">Problem Setting <a class="header-anchor" href="#problem-setting" aria-label="Permalink to &quot;Problem Setting&quot;">​</a></h2><p>As conversations grow longer, agents face a fundamental choice:</p><table tabindex="0"><thead><tr><th>Approach</th><th>Mechanism</th><th>Cost</th><th>Risk</th></tr></thead><tbody><tr><td><strong>Long-context</strong></td><td>Keep full conversation in context window</td><td>Grows linearly with turns</td><td>None (no information loss)</td></tr><tr><td><strong>Memory-based</strong></td><td>Compress older turns into memory representations</td><td>Near-constant after compression</td><td>Information loss from 35:1 compression</td></tr></tbody></table><p>This paper is the first large-scale empirical comparison of these two strategies across multiple task types, conversation lengths, and model sizes.</p><hr><h2 id="core-results-accuracy-comparison" tabindex="-1">Core Results: Accuracy Comparison <a class="header-anchor" href="#core-results-accuracy-comparison" aria-label="Permalink to &quot;Core Results: Accuracy Comparison&quot;">​</a></h2><h3 id="long-context-outperforms-memory" tabindex="-1">Long-Context Outperforms Memory <a class="header-anchor" href="#long-context-outperforms-memory" aria-label="Permalink to &quot;Long-Context Outperforms Memory&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Metric</th><th>Long-Context</th><th>Memory</th><th>Delta</th></tr></thead><tbody><tr><td><strong>Overall accuracy</strong></td><td>Higher</td><td>Lower</td><td><strong>+33.4–35.2pp (long-context wins)</strong></td></tr><tr><td>Short conversations (≤5 turns)</td><td>High</td><td>High</td><td>~Equivalent</td></tr><tr><td>Medium conversations (10–20 turns)</td><td>High</td><td>Moderate</td><td>+25–35pp</td></tr><tr><td>Long conversations (30+ turns)</td><td>Moderate</td><td>Low</td><td>+35pp+</td></tr></tbody></table><p><strong>Key finding</strong>: Long-context consistently outperforms memory-based approaches. The performance gap grows with conversation length.</p><hr><h2 id="economic-break-even-analysis" tabindex="-1">Economic Break-Even Analysis <a class="header-anchor" href="#economic-break-even-analysis" aria-label="Permalink to &quot;Economic Break-Even Analysis&quot;">​</a></h2><h3 id="when-memory-becomes-cost-effective" tabindex="-1">When Memory Becomes Cost-Effective <a class="header-anchor" href="#when-memory-becomes-cost-effective" aria-label="Permalink to &quot;When Memory Becomes Cost-Effective&quot;">​</a></h3><p>At a 100K token context window model:</p><table tabindex="0"><thead><tr><th>Conversation Length</th><th>Long-Context Cost</th><th>Memory Cost</th><th>Winner</th></tr></thead><tbody><tr><td>5 turns</td><td>Low</td><td>Moderate (compression overhead)</td><td>Long-context</td></tr><tr><td><strong>10 turns</strong></td><td>Moderate</td><td><strong>~Equal</strong></td><td><strong>Break-even</strong></td></tr><tr><td>20 turns</td><td>High</td><td>Lower</td><td><strong>Memory (26% cheaper)</strong></td></tr><tr><td>30 turns</td><td>Very high</td><td>Lower</td><td>Memory (40%+ cheaper)</td></tr></tbody></table><p><strong>Break-even point: ~10 turns at 100K token context</strong>. Below 10 turns, long-context is both better and cheaper. Above 10 turns, memory costs less but sacrifices accuracy.</p><h3 id="memory-cost-advantage-at-20-turns" tabindex="-1">Memory Cost Advantage at 20 Turns <a class="header-anchor" href="#memory-cost-advantage-at-20-turns" aria-label="Permalink to &quot;Memory Cost Advantage at 20 Turns&quot;">​</a></h3><p>At 20 conversation turns:</p><ul><li>Long-context: full 20-turn history in context (expensive)</li><li>Memory: compressed representation (~35:1) + recent turns (cheap)</li><li><strong>Memory is 26% cheaper</strong> at 20 turns</li><li>But accuracy is 25–35pp lower</li></ul><hr><h2 id="the-35-1-compression-problem" tabindex="-1">The 35:1 Compression Problem <a class="header-anchor" href="#the-35-1-compression-problem" aria-label="Permalink to &quot;The 35:1 Compression Problem&quot;">​</a></h2><p>Memory systems achieve 35:1 compression ratio — compressing 35 tokens of conversation into 1 token of memory representation.</p><h3 id="information-loss-at-35-1" tabindex="-1">Information Loss at 35:1 <a class="header-anchor" href="#information-loss-at-35-1" aria-label="Permalink to &quot;Information Loss at 35:1&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Information Type</th><th>Preservation Rate at 35:1</th></tr></thead><tbody><tr><td>Main topic/intent</td><td>High (~90%)</td></tr><tr><td>Specific facts (names, numbers, dates)</td><td>Moderate (~60%)</td></tr><tr><td>Reasoning chains</td><td>Low (~40%)</td></tr><tr><td>Nuanced constraints</td><td>Very low (~25%)</td></tr><tr><td>Exact wording</td><td>Minimal (&lt;10%)</td></tr></tbody></table><p><strong>Key finding</strong>: The 35:1 compression ratio preserves broad topics but loses specific facts and nuanced constraints — exactly the information that matters for accurate task completion.</p><hr><h2 id="task-type-sensitivity" tabindex="-1">Task-Type Sensitivity <a class="header-anchor" href="#task-type-sensitivity" aria-label="Permalink to &quot;Task-Type Sensitivity&quot;">​</a></h2><p>Different tasks show different sensitivity to memory compression:</p><table tabindex="0"><thead><tr><th>Task Type</th><th>Long-Context Advantage</th></tr></thead><tbody><tr><td><strong>Multi-step reasoning</strong></td><td>Highest (+45pp)</td></tr><tr><td><strong>Fact-dependent tasks</strong></td><td>High (+38pp)</td></tr><tr><td><strong>Code with context dependencies</strong></td><td>High (+35pp)</td></tr><tr><td>Creative tasks</td><td>Moderate (+20pp)</td></tr><tr><td>Simple retrieval</td><td>Low (+10pp)</td></tr><tr><td>Topic continuation</td><td>Lowest (+5pp)</td></tr></tbody></table><hr><h2 id="memory-architecture-variants-tested" tabindex="-1">Memory Architecture Variants Tested <a class="header-anchor" href="#memory-architecture-variants-tested" aria-label="Permalink to &quot;Memory Architecture Variants Tested&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Memory Type</th><th>Mechanism</th><th>Accuracy vs. Long-Context</th></tr></thead><tbody><tr><td>Summarization memory</td><td>LLM-generated summaries</td><td>−33.4pp</td></tr><tr><td>Vector retrieval memory</td><td>Embedding-based retrieval</td><td>−28.7pp</td></tr><tr><td>Key-value memory</td><td>Structured fact extraction</td><td>−31.2pp</td></tr><tr><td>Hierarchical memory</td><td>Multi-level summaries</td><td>−29.8pp</td></tr><tr><td><strong>Long-context (baseline)</strong></td><td>Full history</td><td><strong>0pp</strong></td></tr></tbody></table><p>No memory architecture approaches long-context accuracy. Vector retrieval memory is the best-performing alternative but still 28.7pp below.</p><hr><h2 id="lost-in-the-middle-effect" tabindex="-1">Lost in the Middle Effect <a class="header-anchor" href="#lost-in-the-middle-effect" aria-label="Permalink to &quot;Lost in the Middle Effect&quot;">​</a></h2><p>At very long contexts (200K+ tokens), long-context models suffer from the &quot;Lost in the Middle&quot; phenomenon (Liu et al. 2023, arxiv 2307.03172):</p><ul><li>Information in the middle of a very long context is underweighted</li><li>Performance on facts from the middle 40% of context drops significantly</li><li>This partially erodes long-context&#39;s advantage at extreme lengths (200K+)</li></ul><p><strong>Practical implication</strong>: Long-context advantage is most reliable in the 10K–100K range. Above 100K, consider hierarchical approaches (retrieval for older context + full context for recent turns).</p><hr><h2 id="recommendations-from-the-paper" tabindex="-1">Recommendations from the Paper <a class="header-anchor" href="#recommendations-from-the-paper" aria-label="Permalink to &quot;Recommendations from the Paper&quot;">​</a></h2><h3 id="decision-framework" tabindex="-1">Decision Framework <a class="header-anchor" href="#decision-framework" aria-label="Permalink to &quot;Decision Framework&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Conversation length?</span></span>
<span class="line"><span>  ≤ 10 turns → Long-context (better accuracy, comparable cost)</span></span>
<span class="line"><span>  11-30 turns, accuracy-critical → Long-context (better accuracy, higher cost)</span></span>
<span class="line"><span>  11-30 turns, cost-constrained → Memory (26% cheaper, 25-35pp accuracy cost)</span></span>
<span class="line"><span>  30+ turns, cost-constrained → Memory (40%+ cheaper, accept accuracy trade-off)</span></span>
<span class="line"><span>  200K+ tokens → Hybrid (memory for oldest turns, full context for recent 50K)</span></span></code></pre></div><h3 id="for-coding-agents-specifically" tabindex="-1">For Coding Agents Specifically <a class="header-anchor" href="#for-coding-agents-specifically" aria-label="Permalink to &quot;For Coding Agents Specifically&quot;">​</a></h3><p>Coding agents have high task-type sensitivity (facts, reasoning chains, constraints) — use long-context preferentially. Memory compression causes bugs from forgotten constraints.</p><hr><h2 id="workspace-relevance" tabindex="-1">Workspace Relevance <a class="header-anchor" href="#workspace-relevance" aria-label="Permalink to &quot;Workspace Relevance&quot;">​</a></h2><p>Directly informs workspace context management strategy:</p><ol><li><strong>Break-even at ~10 turns</strong>: The workspace&#39;s compact triggers (70% context use, per <code>context-management.md</code>) align with this finding. Compacting before 10 turns (at 40-70% context) preserves accuracy while controlling costs.</li><li><strong>26% cheaper at 20 turns with memory</strong>: <code>MEMORY.md</code> dual-layer approach (session summary + Git-tracked decisions) implements the memory strategy for the post-session case — not mid-session, where accuracy matters most.</li><li><strong>35:1 compression loses nuanced constraints</strong>: When <code>/compact</code> is run, nuanced constraints (security rules, per-project conventions) should be explicitly preserved in the compact hint — they&#39;re exactly what 35:1 compression drops.</li><li><strong>−33.4pp accuracy for summarization memory</strong>: The <code>/compact &lt;hint&gt;</code> approach with explicit preservation of key constraints is better than generic summarization — consistent with <code>context-management.md</code> instruction &quot;保留原始任務目標與最近 5 個工具結果.&quot;</li><li><strong>Lost in the Middle at 200K+</strong>: Claude Opus 4.7&#39;s documented long-context regression at 256K+ tokens (per its system card) aligns with this paper&#39;s findings — the accuracy degradation at extreme context lengths is a general phenomenon, not Opus-specific.</li><li><strong>Vector retrieval memory −28.7pp</strong>: The <code>autoresearch</code> loop using memory (<code>MEMORY.md</code>) will degrade accuracy compared to keeping context in window — for high-stakes research tasks, prefer a fresh session with explicit context loading over relying on cross-session memory.</li></ol>`,53)])])}const g=e(a,[["render",s]]);export{p as __pageData,g as default};
